type Option func(*Server)
func WithPort(port int) Option {
    return func(s *Server) { s.port = port }
}
func WithTimeout(d time.Duration) Option {
    return func(s *Server) { s.timeout = d }
}
func NewServer(opts ...Option) *Server {
    s := &Server{port: 8080, timeout: 30 * time.Second}
    for _, opt := range opts {
        opt(s)
    }
    return s
}
srv := NewServer(WithPort(9090), WithTimeout(5*time.Second))

func NewUser(name string, email string) (*User, error) {
    if name == "" {
        return nil, errors.New("name is required")
    }
    if !strings.Contains(email, "@") {
        return nil, errors.New("invalid email")
    }
    return &User{Name: name, Email: email, CreatedAt: time.Now()}, nil
}

var (
    instance *Database
    once     sync.Once
)
func GetDB() *Database {
    once.Do(func() {
        instance = &Database{}
        instance.connect()
    })
    return instance
}

type QueryBuilder struct {
    table   string
    wheres  []string
    orderBy string
    limit   int
}
func NewQuery(table string) *QueryBuilder {
    return &QueryBuilder{table: table}
}
func (q *QueryBuilder) Where(cond string) *QueryBuilder {
    q.wheres = append(q.wheres, cond)
    return q
}
func (q *QueryBuilder) OrderBy(field string) *QueryBuilder {
    q.orderBy = field
    return q
}
func (q *QueryBuilder) Limit(n int) *QueryBuilder {
    q.limit = n
    return q
}
query := NewQuery("users").Where("age > 18").OrderBy("name").Limit(10)

type EmailAddress struct {
    value string
}
func NewEmailAddress(email string) (EmailAddress, error) {
    if !strings.Contains(email, "@") {
        return EmailAddress{}, fmt.Errorf("invalid email: %s", email)
    }
    return EmailAddress{value: strings.ToLower(email)}, nil
}
func (e EmailAddress) String() string { return e.value }

func LoggingMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        start := time.Now()
        next.ServeHTTP(w, r)
        slog.Info("request",
            "method", r.Method,
            "path", r.URL.Path,
            "duration", time.Since(start),
        )
    })
}
http.Handle("/", LoggingMiddleware(AuthMiddleware(myHandler)))

type LegacyPrinter struct{}
func (l *LegacyPrinter) PrintStored(msg string) { fmt.Println("Legacy: " + msg) }

type Printer interface { Print(msg string) }

type PrinterAdapter struct {
    legacy *LegacyPrinter
}
func (a *PrinterAdapter) Print(msg string) {
    a.legacy.PrintStored(msg)
}
func NewPrinterAdapter(l *LegacyPrinter) Printer {
    return &PrinterAdapter{legacy: l}
}

type OrderFacade struct {
    inventory *InventoryService
    payment   *PaymentService
    shipping  *ShippingService
}
func (f *OrderFacade) PlaceOrder(ctx context.Context, order Order) error {
    if err := f.inventory.Reserve(ctx, order.Items); err != nil {
        return fmt.Errorf("inventory: %w", err)
    }
    if err := f.payment.Charge(ctx, order.Total); err != nil {
        return fmt.Errorf("payment: %w", err)
    }
    return f.shipping.Schedule(ctx, order.Address)
}

