u := User{Base: Base{ID: 1, CreatedAt: time.Now()}, Name: "Alice"}
fmt.Println(u.ID) // Promoted field access

Anti-Pattern:
type User struct {
    id        int
    createdAt time.Time
    name      string
} // Duplicating fields across many structs

Code Example:
type Reader interface { Read(p []byte) (n int, err error) }
type Writer interface { Write(p []byte) (n int, err error) }
type ReadWriter interface {
    Reader
    Writer
}
// Consumer only asks for what it needs:
func Process(r Reader) error {
    buf := make([]byte, 1024)
    _, err := r.Read(buf)
    return err
}

type Compressor interface {
    Compress(data []byte) ([]byte, error)
}
type GzipCompressor struct{}
func (g *GzipCompressor) Compress(data []byte) ([]byte, error) {
    var buf bytes.Buffer
    w := gzip.NewWriter(&buf)
    _, err := w.Write(data)
    if err != nil { return nil, err }
    w.Close()
    return buf.Bytes(), nil
}
type Service struct { compressor Compressor }
func NewService(c Compressor) *Service { return &Service{compressor: c} }

type EventBus struct {
    subscribers map[string][]chan Event
    mu          sync.RWMutex
}
func (eb *EventBus) Subscribe(topic string) <-chan Event {
    eb.mu.Lock()
    defer eb.mu.Unlock()
    ch := make(chan Event, 16)
    eb.subscribers[topic] = append(eb.subscribers[topic], ch)
    return ch
}
func (eb *EventBus) Publish(topic string, event Event) {
    eb.mu.RLock()
    defer eb.mu.RUnlock()
    for _, ch := range eb.subscribers[topic] {
        select {
        case ch <- event:
        default: // Drop if subscriber is slow
        }
    }
}

type Command interface {
    Execute() error
    Undo() error
}
type CreateUserCmd struct {
    repo UserRepo
    user User
}
func (c *CreateUserCmd) Execute() error {
    return c.repo.Create(c.user)
}
func (c *CreateUserCmd) Undo() error {
    return c.repo.Delete(c.user.ID)
}
func RunCommands(cmds []Command) error {
    for i, cmd := range cmds {
        if err := cmd.Execute(); err != nil {
            for j := i - 1; j >= 0; j-- { cmds[j].Undo() }
            return err
        }
    }
    return nil
}

func gen(nums ...int) <-chan int {
    out := make(chan int)
    go func() {
        defer close(out)
        for _, n := range nums { out <- n }
    }()
    return out
}
func sq(in <-chan int) <-chan int {
    out := make(chan int)
    go func() {
        defer close(out)
        for n := range in { out <- n * n }
    }()
    return out
}
// Usage: for v := range sq(sq(gen(2, 3, 4))) { fmt.Println(v) }

type Handler interface {
    Handle(req Request) (Response, error)
    SetNext(h Handler)
}
type AuthHandler struct{ next Handler }
func (a *AuthHandler) Handle(req Request) (Response, error) {
    if req.Token == "" {
        return Response{}, errors.New("unauthorized")
    }
    if a.next != nil { return a.next.Handle(req) }
    return Response{}, nil
}
func (a *AuthHandler) SetNext(h Handler) { a.next = h }

var statusText = map[int]string{
    200: "OK",
    201: "Created",
    400: "Bad Request",
    404: "Not Found",
    500: "Internal Server Error",
}
func StatusText(code int) string {
    if text, ok := statusText[code]; ok {
        return text
    }
    return "Unknown"
}

Anti-Pattern:
func StatusText(code int) string {
    if code == 200 { return "OK" }
    if code == 201 { return "Created" }
    // ... long chain of if/else
}

