func process(val any) string {
    switch v := val.(type) {
    case string:
        return strings.ToUpper(v)
    case int:
        return strconv.Itoa(v)
    case error:
        return "error: " + v.Error()
    default:
        return fmt.Sprintf("%v", v)
    }
}

type Weekday int
const (
    Sunday Weekday = iota
    Monday
    Tuesday
    Wednesday
    Thursday
    Friday
    Saturday
)
func (d Weekday) String() string {
    names := [...]string{"Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"}
    if d < Sunday || d > Saturday { return "Unknown" }
    return names[d]
}

func CompressAndEncrypt(w io.Writer, key []byte) (io.WriteCloser, error) {
    block, err := aes.NewCipher(key)
    if err != nil { return nil, err }
    stream := cipher.NewCTR(block, iv)
    cryptWriter := &cipher.StreamWriter{S: stream, W: w}
    return gzip.NewWriter(cryptWriter), nil
}
// Data flows: input -> gzip -> encrypt -> output

