})

limiter := rate.NewLimiter(rate.Every(time.Second), 10) // 10 req/s
func handler(w http.ResponseWriter, r *http.Request) {
    if !limiter.Allow() {
        http.Error(w, "rate limit exceeded", http.StatusTooManyRequests)
        return
    }
    // Process request
}
// Or blocking: if err := limiter.Wait(ctx); err != nil { return err }

sem := make(chan struct{}, 10) // Max 10 concurrent
var wg sync.WaitGroup
for _, url := range urls {
    wg.Add(1)
    go func(u string) {
        defer wg.Done()
        sem <- struct{}{}        // Acquire
        defer func() { <-sem }() // Release
        resp, err := http.Get(u)
        if err != nil { return }
        defer resp.Body.Close()
        // Process response
    }(url)
}
wg.Wait()

type Broker[T any] struct {
    mu   sync.RWMutex
    subs map[string][]chan T
}
func (b *Broker[T]) Subscribe(topic string, bufSize int) <-chan T {
    b.mu.Lock()
    defer b.mu.Unlock()
    ch := make(chan T, bufSize)
    b.subs[topic] = append(b.subs[topic], ch)
    return ch
}
func (b *Broker[T]) Publish(topic string, msg T) {
    b.mu.RLock()
    defer b.mu.RUnlock()
    for _, ch := range b.subs[topic] {
        select {
        case ch <- msg:
        default:
        }
    }
}

type Role string
const (
    RoleUser       Role = "user"
    RoleAdmin      Role = "admin"
    RoleSuperAdmin Role = "superadmin"
)
var roleLevel = map[Role]int{RoleUser: 1, RoleAdmin: 2, RoleSuperAdmin: 3}

func RequireRole(minRole Role) func(http.Handler) http.Handler {
    return func(next http.Handler) http.Handler {
        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            claims, ok := r.Context().Value(ClaimsKey).(Claims)
            if !ok {
                http.Error(w, `{"error":"unauthorized"}`, 401)
                return
            }
            if roleLevel[Role(claims.Role)] < roleLevel[minRole] {
                http.Error(w, `{"error":"forbidden"}`, 403)
                return
            }
            next.ServeHTTP(w, r)
        })
    }
}
// r.With(Auth(secret), RequireRole(RoleAdmin)).Get("/admin/stats", ...)

Anti-Pattern:
func (h *Handler) ListUsers(w http.ResponseWriter, r *http.Request) {
    claims := r.Context().Value("claims").(Claims)
    if claims.Role != "admin" && claims.Role != "superadmin" {
        http.Error(w, "forbidden", 403)
        return
    }
    // role check duplicated in every handler
}
